if ( ! defined( 'ABSPATH' ) ) {
	exit;
}

const HEA_LTH_OPS_VERSION = '0.2.0';
/**
 * Persist non-secret deployment metadata for independent release verification.
 *
 * @param string $deployment_id Deployment identifier generated by the release pipeline.
 */
function hea_lth_ops_store_deployment( string $deployment_id ): void {

	$deployment_id = sanitize_text_field( $deployment_id );
	if ( '' === $deployment_id || 1 !== preg_match( '/^[a-zA-Z0-9._-]{8,128}$/', $deployment_id ) ) {
		return;
	}

	update_option(
		'hea_lth_ops_last_deployment',
		array(
			'deployment_id' => $deployment_id,
			'version'       => HEA_LTH_OPS_VERSION,
			'deployed_at'   => gmdate( 'c' ),
		),
		false
	);
}

/**
 * Record an authenticated agent deployment without persisting credentials.
 */
function hea_lth_ops_record_deployment(): void {

	$deployment_id = isset( $_SERVER['HTTP_X_HEA_LTH_DEPLOYMENT_ID'] )
	? sanitize_text_field( wp_unslash( (string) $_SERVER['HTTP_X_HEA_LTH_DEPLOYMENT_ID'] ) )
		: '';

	hea_lth_ops_store_deployment(
		$deployment_id
	);
}
register_activation_hook( __FILE__, 'hea_lth_ops_record_deployment' );
