	return array(
		'aesthetic-medicine'     => __( 'רפואה אסתטית', 'hea-lth-ops' ),
		'plastic-surgery'        => __( 'כירורגיה פלסטית', 'hea-lth-ops' ),
		'hair-transplant'        => __( 'השתלות שיער ונשירת שיער', 'hea-lth-ops' ),
		'private-medicine'       => __( 'רפואה פרטית', 'hea-lth-ops' ),
		'diagnostics-wellness'   => __( 'בדיקות, אבחון ו-Wellness', 'hea-lth-ops' ),
		'professional-join'      => __( 'הצטרפות מקצוענים', 'hea-lth-ops' ),
